#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int* days = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            days[i] = 0;
        }
        int* temp = (int*)malloc(N * sizeof(int));
        int tempSize = N;
        int day = 1;
        while (1) {
            int newTempSize = 0;
            for (int i = 0; i < tempSize; i++) {
                if (i == 0 || i == tempSize - 1) {
                    temp[newTempSize++] = A[i];
                } else if (A[i] >= A[i - 1] && A[i] >= A[i + 1]) {
                    temp[newTempSize++] = A[i];
                } else {
                    days[i] = day;
                }
            }
            if (newTempSize == tempSize) {
                break;
            }
            tempSize = newTempSize;
            day++;
        }
        for (int i = 0; i < N; i++) {
            printf("%d ", days[i]);
        }
        printf("\n");
        free(A);
        free(days);
        free(temp);
    }
    return 0;
}

