import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = scanner.nextInt();
            }
            int[] days = new int[N];
            int[] temp = new int[N];
            int tempSize = N;
            int day = 1;
            while (true) {
                int newTempSize = 0;
                for (int i = 0; i < tempSize; i++) {
                    if (i == 0 || i == tempSize - 1) {
                        temp[newTempSize++] = A[i];
                    } else if (A[i] >= A[i - 1] && A[i] >= A[i + 1]) {
                        temp[newTempSize++] = A[i];
                    } else {
                        days[i] = day;
                    }
                }
                if (newTempSize == tempSize) {
                    break;
                }
                tempSize = newTempSize;
                day++;
            }
            for (int i = 0; i < N; i++) {
                System.out.print(days[i] + " ");
            }
            System.out.println();
        }
    }
}

