const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    const A = readline().split(' ').map(x => parseInt(x));
    const days = new Array(N).fill(0);
    let temp = A.slice();
    let tempSize = N;
    let day = 1;
    while (true) {
        let newTempSize = 0;
        for (let j = 0; j < tempSize; j++) {
            if (j === 0 || j === tempSize - 1) {
                temp[newTempSize] = A[j];
                newTempSize++;
            } else if (A[j] >= A[j - 1] && A[j] >= A[j + 1]) {
                temp[newTempSize] = A[j];
                newTempSize++;
            } else {
                days[j] = day;
            }
        }
        if (newTempSize === tempSize) {
            break;
        }
        tempSize = newTempSize;
        day++;
    }
    console.log(days.join(' '));
